 import React, { useEffect, useRef } from "react";

 export function EmbeddedChatNotice() {
   const noticeRef = useRef(null);

   useEffect(() => {
     const onMessage = (event) => {
       if (!event.origin.includes("corpchat.com")) 
return;
       if (event.data?.type !== "CHAT_NOTICE") 
return;
       if (!noticeRef.current) return;

       noticeRef.current.innerHTML = event.data.body;
     };

     window.addEventListener("message", onMessage);
     return () => 
window.removeEventListener("message", onMessage);
   }, []);

   return <div ref={noticeRef} 
className="chat-notice" />;
 }

import React, { useMemo } from "react";

export function ProductSearchHeader() {
  const query = useMemo(() => {
    const params = new URLSearchParams(window.location.search);
    return params.get("q") ?? "";
  }, []);

  const summaryHtml = useMemo(() => {
    if (!query) return "Showing all products";
    return `Showing results for <mark>${query}</mark>`;
  }, [query]);

  return (
    <h2
      className="text-xl font-semibold"
      dangerouslySetInnerHTML={{ __html: summaryHtml }}
    />
  );
}

import React, { useMemo } from "react";

export function ProfileBioPreview() {
  const draftBio = useMemo(
    () => localStorage.getItem("profile.bioDraft") ?? "",
    []
  );

  const previewHtml = useMemo(() => {
    return draftBio.replace(/\n/g, "<br />");
  }, [draftBio]);

  return (
    <section className="card">
      <h3>Bio Preview</h3>
      <p dangerouslySetInnerHTML={{ __html: previewHtml }} />
    </section>
  );
}

 import React, { useEffect, useRef } from "react";

 export function ReferralAttributionNote() {
   const noteRef = useRef(null);

   useEffect(() => {
     if (!document.referrer || !noteRef.current) 
return;

     const campaign =
       new 
URL(document.referrer).searchParams.get("campaign") 
?? "direct";

     noteRef.current.insertAdjacentHTML(
       "beforeend",
       `You're viewing this page from campaign: 
<b>${campaign}</b>`
     );
   }, []);

   return <small ref={noteRef} 
className="referral-note" />;
 }

import React, { useEffect, useRef } from "react";

export function ReferralWelcomeCard() {
  const messageRef = useRef(null);

  useEffect(() => {
    const referrer =
      new URLSearchParams(window.location.search).get("ref") ?? "a teammate";

    if (!messageRef.current) return;
    messageRef.current.insertAdjacentHTML(
      "beforeend",
      `<strong>Welcome aboard!</strong> Referred by ${referrer}.`
    );
  }, []);

  return <div ref={messageRef} className="welcome-card" />;
}

